<?php require_once __DIR__ . '/../includes/header.php'; require_once __DIR__ . '/../includes/csrf.php';
if($_SERVER['REQUEST_METHOD']==='POST'){csrf_check();$pdo->prepare('INSERT INTO proposals(lead_id,title,proposal_date,amount,status,description,notes,created_by,created_at) VALUES (?,?,?,?,?,?,?,?,NOW())')->execute([$_POST['lead_id'],$_POST['title'],$_POST['proposal_date'],$_POST['amount'],$_POST['status'],$_POST['description'],$_POST['notes'],current_user()['id']]);header('Location: /proposals/index.php');exit;}
$rows=$pdo->query('SELECT p.*,l.full_name lead_name FROM proposals p LEFT JOIN leads l ON l.id=p.lead_id ORDER BY p.proposal_date DESC')->fetchAll();
$leads=$pdo->query('SELECT id,full_name FROM leads WHERE deleted_at IS NULL ORDER BY full_name')->fetchAll();
?><h3>Proposals</h3><div class="card card-body mb-3"><form method="post" class="row g-2"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><div class="col-md-2"><select class="form-select" name="lead_id"><?php foreach($leads as $l):?><option value="<?= (int)$l['id'] ?>"><?= e($l['full_name']) ?></option><?php endforeach;?></select></div><div class="col-md-2"><input class="form-control" name="title" placeholder="Proposal title" required></div><div class="col-md-2"><input type="date" class="form-control" name="proposal_date" required></div><div class="col-md-1"><input type="number" step="0.01" class="form-control" name="amount" placeholder="Amount"></div><div class="col-md-2"><select class="form-select" name="status"><option>Draft</option><option>Sent</option><option>Under Review</option><option>Accepted</option><option>Rejected</option></select></div><div class="col-md-3"><button class="btn btn-primary w-100">Add Proposal</button></div><div class="col-md-6"><input class="form-control" name="description" placeholder="Short description"></div><div class="col-md-6"><input class="form-control" name="notes" placeholder="Notes"></div></form></div>
<div class="table-responsive"><table class="table"><thead><tr><th>Title</th><th>Lead</th><th>Date</th><th>Amount</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?= e($r['title']) ?></td><td><?= e($r['lead_name']) ?></td><td><?= e($r['proposal_date']) ?></td><td><?= e((string)$r['amount']) ?></td><td><span class="badge bg-<?= badge_class('proposal',$r['status']) ?>"><?= e($r['status']) ?></span></td></tr><?php endforeach;?></tbody></table></div>
